pragma solidity ^0.8.24;

import {FHE, ebool, euint64} from "@fhevm/solidity/lib/FHE.sol";
import {ZamaEthereumConfig} from "@fhevm/solidity/config/ZamaConfig.sol";
import {IERC7984} from "@openzeppelin/confidential-contracts/interfaces/IERC7984.sol";
import {IERC7984Receiver} from "@openzeppelin/confidential-contracts/interfaces/IERC7984Receiver.sol";
import {ZTorPool} from "./ZTorPool.sol";
import {IZTorLiquidityStats} from "./interfaces/IZTorLiquidityStats.sol";
import {IZTorVerifier} from "./interfaces/IZTorVerifier.sol";

/// @title Fixed-denomination pool backed by ERC-7984 confidential tokens
contract ZTorConfidentialPool is ZTorPool, ZamaEthereumConfig, IERC7984Receiver {
    IERC7984 public immutable confidentialToken;

    struct PendingDeposit {
        bool exists;
        bytes32 acceptedHandle;
    }

    /// @dev Commitments whose tokens arrived but whose amount is not yet confirmed.
    mapping(bytes32 => PendingDeposit) public pendingDeposits;

    event DepositPending(bytes32 indexed commitment, bytes32 acceptedHandle);
    event DepositRejected(bytes32 indexed commitment);

    error EthNotAccepted();
    error UseConfidentialDeposit();
    error ZeroToken();
    error InvalidCommitmentPayload();
    error CommitmentAlreadyPending();
    error NoPendingDeposit();

    constructor(
        IZTorVerifier _verifier,
        IZTorLiquidityStats _stats,
        IERC7984 _token,
        uint256 _denomination,
        uint256 _anonymityDelay,
        uint32 _levels
    ) ZTorPool(_verifier, _stats, _denomination, _anonymityDelay, _levels) {
        if (address(_token) == address(0)) revert ZeroToken();
        confidentialToken = _token;
    }

    /// @inheritdoc ZTorPool
    function deposit(bytes32) external payable override {
        if (msg.value != 0) revert EthNotAccepted();
        revert UseConfidentialDeposit();
    }

    /// @notice ERC-7984 transfer callback used as the deposit entrypoint. Records the
    /// commitment as pending and publishes an encrypted `amount == denomination` check;
    /// the returned bool also drives the token's refund when the amount is wrong. Only
    /// the confidential token may call it, so the `amount` handle cannot be spoofed.
    function onConfidentialTransferReceived(
        address,
        address,
        euint64 amount,
        bytes calldata data
    ) external returns (ebool) {
        if (msg.sender != address(confidentialToken)) revert ZeroToken();
        if (data.length != 32) revert InvalidCommitmentPayload();
        bytes32 commitment = abi.decode(data, (bytes32));
        if (commitments[commitment]) revert CommitmentAlreadyUsed();
        if (pendingDeposits[commitment].exists) revert CommitmentAlreadyPending();
        if (uint256(commitment) >= FIELD_SIZE) revert CommitmentNotInField();

        ebool accepted = FHE.eq(amount, FHE.asEuint64(uint64(denomination)));
        FHE.allowThis(accepted);
        FHE.makePubliclyDecryptable(accepted);
        FHE.allowTransient(accepted, msg.sender);

        bytes32 handle = FHE.toBytes32(accepted);
        pendingDeposits[commitment] = PendingDeposit({exists: true, acceptedHandle: handle});
        emit DepositPending(commitment, handle);

        return accepted;
    }

    /// @notice Finalize a pending deposit from the verified public decryption of its
    /// amount check. The commitment becomes a spendable note only if the amount matched.
    /// Permissionless: KMS signatures are verified on-chain so the result cannot be forged.
    function finalizeDeposit(
        bytes32 commitment,
        bytes calldata abiEncodedAccepted,
        bytes calldata decryptionProof
    ) external nonReentrant {
        PendingDeposit memory pending = pendingDeposits[commitment];
        if (!pending.exists) revert NoPendingDeposit();

        bytes32[] memory handles = new bytes32[](1);
        handles[0] = pending.acceptedHandle;
        FHE.checkSignatures(handles, abiEncodedAccepted, decryptionProof);
        bool accepted = abi.decode(abiEncodedAccepted, (bool));

        delete pendingDeposits[commitment];

        if (accepted) {
            _registerDeposit(commitment);
        } else {
            emit DepositRejected(commitment);
        }
    }

    /// @dev Unused; confidential deposits enter through the ERC-7984 callback.
    // solhint-disable-next-line no-empty-blocks
    function _processDeposit() internal override {}

    function token() external view returns (address) {
        return address(confidentialToken);
    }

    function _processWithdraw(
        address payable recipient,
        address payable relayer,
        uint256 fee
    ) internal override {
        uint64 net = uint64(denomination - fee);
        if (net > 0) {
            euint64 payout = FHE.asEuint64(net);
            FHE.allowTransient(payout, address(confidentialToken));
            confidentialToken.confidentialTransfer(recipient, payout);
        }
        if (fee > 0) {
            euint64 relayerFee = FHE.asEuint64(uint64(fee));
            FHE.allowTransient(relayerFee, address(confidentialToken));
            confidentialToken.confidentialTransfer(relayer, relayerFee);
        }
    }
}
","keccak256":"0x21df6b01faa9a0c03aa79d9263dbced62b7ca785141c26fb42384d2c3f82a818","license":"MIT"},"contracts/ZTorLiquidityStats.sol":{"content":"// SPDX-License-Identifier: MIT

pragma solidity ^0.8.24;



import {FHE, ebool, euint32} from "@fhevm/solidity/lib/FHE.sol";

import {ZamaEthereumConfig} from "@fhevm/solidity/config/ZamaConfig.sol";

import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";

import {IZTorLiquidityStats} from "./interfaces/IZTorLiquidityStats.sol";



/// @title Encrypted per-pool liquidity counter (FHE layer)

/// @notice Tracks the number of unspent notes per pool as an encrypted

/// euint32. Only the owner is granted decryption rights — there is no

/// global backdoor and no encrypted value is ever emitted in events.

contract ZTorLiquidityStats is IZTorLiquidityStats, ZamaEthereumConfig, Ownable {

    mapping(address => bool) public registeredPools;

    mapping(address => bool) public registrars;

    mapping(address => euint32) private _activeNotes;



    event PoolRegistered(address indexed pool);

    event RegistrarUpdated(address indexed account, bool allowed);



    error NotRegisteredPool();

    error AlreadyRegistered();

    error UnauthorizedRegistrar();



    modifier onlyPool() {

        if (!registeredPools[msg.sender]) revert NotRegisteredPool();

        _;

    }



    constructor() Ownable(msg.sender) {}



    function setRegistrar(address account, bool allowed) external onlyOwner {

        registrars[account] = allowed;

        emit RegistrarUpdated(account, allowed);

    }



    function registerPool(address pool) external {

        if (msg.sender != owner() && !registrars[msg.sender]) revert UnauthorizedRegistrar();

        if (registeredPools[pool]) revert AlreadyRegistered();

        registeredPools[pool] = true;

        emit PoolRegistered(pool);

    }



    function recordDeposit() external override onlyPool {

        euint32 count = _activeNotes[msg.sender];

        if (!FHE.isInitialized(count)) {

            count = FHE.asEuint32(0);

        }

        count = FHE.add(count, 1);

        _activeNotes[msg.sender] = count;

        FHE.allowThis(count);

        FHE.allow(count, owner());

        FHE.makePubliclyDecryptable(count);

    }



    function recordWithdraw() external override onlyPool {

        euint32 count = _activeNotes[msg.sender];

        if (!FHE.isInitialized(count)) {

            count = FHE.asEuint32(0);

        }

        ebool hasNotes = FHE.gt(count, FHE.asEuint32(0));

        count = FHE.select(hasNotes, FHE.sub(count, 1), FHE.asEuint32(0));

        _activeNotes[msg.sender] = count;

        FHE.allowThis(count);

        FHE.allow(count, owner());

        FHE.makePubliclyDecryptable(count);

    }



    /// @notice Encrypted handle of the active-note count for `pool`.

    function activeNotes(address pool) external view returns (euint32) {

        return _activeNotes[pool];

    }

}

","keccak256":"0x3227585ac1e452af34347f11908bdd5efdbf7db1324e61b5b94d4db565aa900b","license":"MIT"},"contracts/ZTorPool.sol":{"content":"// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {ReentrancyGuard} from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import {MerkleTreeWithHistory} from "./MerkleTreeWithHistory.sol";
import {IZTorLiquidityStats} from "./interfaces/IZTorLiquidityStats.sol";
import {IZTorPool} from "./interfaces/IZTorPool.sol";
import {IZTorVerifier} from "./interfaces/IZTorVerifier.sol";

/// @title Fixed-denomination privacy pool (unlink layer)
/// @notice Deposits insert a commitment into the Merkle tree; withdrawals
/// spend a nullifier backed by a Groth16 membership proof. The anonymity
/// delay is enforced on the *root* age, never on an individual deposit, so
/// the contract never learns which note is being spent.
abstract contract ZTorPool is IZTorPool, MerkleTreeWithHistory, ReentrancyGuard {
    IZTorVerifier public immutable verifier;
    IZTorLiquidityStats public immutable stats;
    uint256 public immutable override denomination;
    uint256 public immutable anonymityDelay;

    mapping(bytes32 => bool) public nullifierHashes;
    mapping(bytes32 => bool) public commitments;

    error ZeroDenomination();
    error CommitmentAlreadyUsed();
    error CommitmentNotInField();
    error NoteAlreadySpent();
    error UnknownRoot();
    error RootTooRecent();
    error InvalidProof();
    error FeeExceedsDenomination();
    error FeeWithoutRelayer();

    constructor(
        IZTorVerifier _verifier,
        IZTorLiquidityStats _stats,
        uint256 _denomination,
        uint256 _anonymityDelay,
        uint32 _levels
    ) MerkleTreeWithHistory(_levels) {
        if (_denomination == 0) revert ZeroDenomination();
        verifier = _verifier;
        stats = _stats;
        denomination = _denomination;
        anonymityDelay = _anonymityDelay;
    }

    /// @notice Deposit exactly `denomination`, registering `commitment`.
    /// @param commitment Poseidon(nullifier, secret), computed client-side.
    function deposit(bytes32 commitment) external payable virtual nonReentrant {
        _processDeposit();
        _registerDeposit(commitment);
    }

    /// @dev Shared commitment registration for legacy and confidential deposits.
    function _registerDeposit(bytes32 commitment) internal {
        if (commitments[commitment]) revert CommitmentAlreadyUsed();
        if (uint256(commitment) >= FIELD_SIZE) revert CommitmentNotInField();

        commitments[commitment] = true;
        uint32 leafIndex = _insert(commitment);

        if (address(stats) != address(0)) stats.recordDeposit();

        // solhint-disable-next-line not-rely-on-time
        emit Deposit(commitment, leafIndex, block.timestamp);
    }

    /// @notice Withdraw `denomination` to `recipient` by proving membership.
    /// @param proof abi.encode(uint256[2] a, uint256[2][2] b, uint256[2] c).
    /// @param root A historical Merkle root at least `anonymityDelay` old.
    /// @param nullifierHash Poseidon(nullifier); spent exactly once.
    /// @param relayer Paid `fee` out of the denomination so the recipient
    /// address never needs gas. Both values are bound inside the proof, so a
    /// relayer cannot raise its fee or redirect the payout.
    function withdraw(
        bytes calldata proof,
        bytes32 root,
        bytes32 nullifierHash,
        address payable recipient,
        address payable relayer,
        uint256 fee
    ) external override nonReentrant {
        if (nullifierHashes[nullifierHash]) revert NoteAlreadySpent();
        if (!isKnownRoot(root)) revert UnknownRoot();
        if (fee > denomination) revert FeeExceedsDenomination();
        if (fee > 0 && relayer == address(0)) revert FeeWithoutRelayer();
        // solhint-disable-next-line not-rely-on-time
        if (block.timestamp < rootTimestamps[root] + anonymityDelay) revert RootTooRecent();

        (uint256[2] memory a, uint256[2][2] memory b, uint256[2] memory c) = abi.decode(
            proof,
            (uint256[2], uint256[2][2], uint256[2])
        );
        uint256[5] memory pubSignals = [
            uint256(root),
            uint256(nullifierHash),
            uint256(uint160(address(recipient))),
            uint256(uint160(address(relayer))),
            fee
        ];
        if (!verifier.verifyProof(a, b, c, pubSignals)) revert InvalidProof();

        nullifierHashes[nullifierHash] = true;
        _processWithdraw(recipient, relayer, fee);

        if (address(stats) != address(0)) stats.recordWithdraw();

        emit Withdrawal(recipient, nullifierHash, relayer, fee);
    }

    function _processDeposit() internal virtual;

    function _processWithdraw(
        address payable recipient,
        address payable relayer,
        uint256 fee
    ) internal virtual;
}
